def compute_score() -> tuple[str, float]:
    # We'll use a VLM to check the screenshot for a diagram and its position in a single call.
    # Find slide 8 screenshot
    images = [s.image_path for s in modified_ppt_screenshots if s.slide_number == 8]
    if not images:
        return ("No screenshot available for slide 8.", 0.0)

    prompt = (
        "Analyze the slide for a simple diagram (such as a box/ellipse/arrow/line) showing the IP address 128.119.245.12 connected to Port 80, with clear text labels for both. "
        "Based on its presence and location, answer with ONLY one of the following words: 'CORRECT', 'WRONG_POSITION', or 'NONE'.\n"
        "- 'CORRECT': The diagram exists and is located directly under the text 'gaia.cs.umass.edu'.\n"
        "- 'WRONG_POSITION': The diagram exists but is NOT located directly under the bullet point containing 'gaia.cs.umass.edu'.\n"
        "- 'NONE': The diagram does not exist at all."
    )
    response = vlm_call(prompt, images).lower()

    if "correct" in response:
        return ("Diagram with correct labels detected under 'gaia.cs.umass.edu' on slide 8.", 1.0)
    elif "wrong_position" in response:
        return ("Diagram with correct labels detected on slide 8, but not in the correct position.", 0.7)
    else:  # "none" or anything else
        return ("No correct diagram detected on slide 8.", 0.0)

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    orig = Presentation(original_ppt_path)
    mod = Presentation(modified_ppt_path)
    # For each slide except slide 8
    for slide_idx in range(len(orig.slides)):
        if slide_idx == 7:
            continue
        orig_slide = orig.slides[slide_idx]
        mod_slide = mod.slides[slide_idx] if slide_idx < len(mod.slides) else None
        if not mod_slide:
            continue  # Slide might be deleted, not expected for this task
        def extract_text_fontsize(shape):
            data = []
            if not shape.has_text_frame:
                return data
            for para in shape.text_frame.paragraphs:
                for run in para.runs:
                    if run.text.strip():
                        size = run.font.size.pt if run.font.size else None
                        data.append((run.text.strip(), size))
            return data
        def get_slide_text_fontsize(slide):
            out = []
            for shape in slide.shapes:
                out.extend(extract_text_fontsize(shape))
            return out
        orig_text_sizes = get_slide_text_fontsize(orig_slide)
        mod_text_sizes = get_slide_text_fontsize(mod_slide)
        orig_map = {}
        for t, sz in orig_text_sizes:
            orig_map.setdefault(t, []).append(sz)
        mod_map = {}
        for t, sz in mod_text_sizes:
            mod_map.setdefault(t, []).append(sz)
        # For every text, check font sizes unchanged
        for text in orig_map:
            if text not in mod_map:
                continue
            if orig_map[text] != mod_map[text]:
                return (f"Font size for text '{text}' changed on slide {slide_idx+1}.", 0.0)
    return ("No text/font changes on other slides.", 1.0)

